p=A.t8("\uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8\ub97c \uc9c4\ud589\ud558\ub824 \ud560 \ub54c \uc801\ud569\ud55c \ud300\uc6d0\uc744 \ucc3e\uae30 \uc5b4\ub824\uc6b4 \ubb38\uc81c\uc810\uc5d0 \ucc29\uc548\ud588\uc2b5\ub2c8\ub2e4.\n\uc18c\uac1c\ud305 \uc571\uc758 UX\uc5d0\uc11c \uc601\uac10\uc744 \ubc1b\uc544, \uac1c\ubc1c\uc790\ub4e4\uc774 \uc11c\ub85c\uc758 \uae30\uc220 \uc2a4\ud0dd\uacfc \ud3ec\ud2b8\ud3f4\ub9ac\uc624\ub97c \n\uc9c1\uad00\uc801\uc73c\ub85c \ud655\uc778\ud558\uace0 \uad00\uc2ec\uc0ac\uac00 \ub9de\ub294 \ud300\uc6d0\uc744 \uc27d\uac8c \ucc3e\uc744 \uc218 \uc788\ub294 \ud50c\ub7ab\ud3fc\uc744 \uad6c\uc0c1\ud588\uc2b5\ub2c8\ub2e4.\n",j,null,"\uac1c\ubc1c\uc790\ub4e4\uc774 \uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8 \ud300\uc6d0\uc744 \ud6a8\uacfc\uc801\uc73c\ub85c \ucc3e\uace0 \uc18c\ud1b5\ud560 \uc218 \uc788\ub294 \ub9e4\uce6d \ud50c\ub7ab\ud3fc\uc785\ub2c8\ub2e4.","https://github.com/Nangman-Archive/CoPro_iOS","2","images/copro.png",A.a(["\uac1c\ubc1c\uc790 \ucd94\ucc9c \uc54c\uace0\ub9ac\uc998 \uace0\ub3c4\ud654","\ud504\ub85c\uc81d\ud2b8 \uc9c4\ud589 \uad00\ub9ac \ub300\uc2dc\ubcf4\ub4dc \ucd94\uac00","\uba58\ud1a0-\uba58\ud2f0 \ub9e4\uce6d \uc2dc\uc2a4\ud15c \ub3c4\uc785","\uae30\uc220 \ud2b8\ub80c\ub4dc \uae30\ubc18 \ub9e4\uce6d \uae30\ub2a5 \uac1c\ubc1c"],k),i,"Firebase\ub97c \ud65c\uc6a9\ud55c \uc2e4\uc2dc\uac04 \ucc44\ud305 \uc2dc\uc2a4\ud15c\uacfc \ub370\uc774\ud130\ubca0\uc774\uc2a4 \uad6c\ud604\uc744 \ud1b5\ud574 \n\uc2e4\uc2dc\uac04 \uc560\ud50c\ub9ac\ucf00\uc774\uc158 \uac1c\ubc1c \uacbd\ud5d8\uc744 \uc313\uc558\uc2b5\ub2c8\ub2e4. \ub610\ud55c GitHub API \uc5f0\ub3d9\uacfc\n\uce74\ub4dc \uc2a4\uc640\uc774\ud504 \uc778\ud130\ud398\uc774\uc2a4 \uad6c\ud604\uc744 \ud1b5\ud574 \ubcf5\uc7a1\ud55c \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \uad6c\ud604\ud558\ub294 \n\uc5ed\ub7c9\uc744 \ud0a4\uc6b8 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\n","2023.10.22 ~ 2024.02.10",h,"\uc0ac\uc774\ub4dc \ud504\ub85c\uc81d\ud2b8 \ud300\uc6d0 \ub9e4\uce6d \ubc0f \uac1c\ubc1c\uc790 \ub124\ud2b8\uc6cc\ud0b9 \ud50c\ub7ab\ud3fc","iOS 3\uc778, Back-end 2\uc778",g,"Copro",p)
g=A.a(["\ubbf8\uc138\uba3c\uc9c0 \ub18d\ub3c4\ub97c \uc2dc\uac01\uc801 \ud6a8\uacfc\ub85c \ud45c\ud604\ud558\ub294 \uc5d0\ub2c8\uba54\uc774\uc158","\ub0a0\uc528 \uc804\ud658 \uc2dc \ud654\uba74 \uc804\uccb4\uac00 \ubcc0\ud654\ud558\ub294 \ubc30\uacbd \uc560\ub2c8\uba54\uc774\uc158","\ub0a0\uc528\uc5d0 \uc5b4\uc6b8\ub9ac\ub294 \uc637\ucc28\ub9bc\uacfc \uc74c\uc2dd\uc744 \ucd94\ucc9c","\ud654\uba74 \uc804\ud658\uac04 \uc790\uc5f0\uc2a4\ub7ec\uc6b4 UI \ubc30\uce58 \uc5d0\ub2c8\uba54\uc774\uc158"],k)
h=A.a(["Swift","UIKit","Alamofire","Snapkit","Then"],k)
i=A.a(["\ub0a0\uc528\uc5d0 \ub530\ub978 \ubc30\uacbd \ubc0f UI \ubcc0\uacbd","\ubbf8\uc138 \uba3c\uc9c0 \ub18d\ub3c4\uc5d0 \ub530\ub978 \uc5d0\ub2c8\uba54\uc774\uc158 \uc870\uc815","\uc9c0\uc5ed \ubcc0\uacbd\uc5d0 \ub530\ub978 \ub3d9\uae30\ud654 \uc791\uc5c5"],k)
j=A.a(["UI/UX \ub514\uc790\uc778 \ubc0f \uc560\ub2c8\uba54\uc774\uc158 \uc2dc\uc2a4\ud15c \uac1c\ubc1c","OpenWeatherMap API \uc5f0\ub3d9 \ubc0f \ub370\uc774\ud130 \ucc98\ub9ac","\ub0a0\uc528 \uc0c1\ud0dc\ubcc4 \uc560\ub2c8\uba54\uc774\uc158 \ud6a8\uacfc \uad6c\ud604","\ubbf8\uc138\uba3c\uc9c0 \ub370\uc774\ud130 \uc2dc\uac01\ud654 \ucef4\ud3ec\ub10c\ud2b8 \uac1c\ubc1c"],k)
o=A.a([new A.d5("\ub0a0\uc528 \uc0c1\ud0dc\uc5d0 \ub530\ub978 \ub3d9\uc801 UI \ub80c\ub354\ub9c1 \ubb38\uc81c","\ub0a0\uc528 \ubcc0\ud654\uc5d0 \ub530\ub77c \ubc30\uacbd \uc774\ubbf8\uc9c0\uc640 UI \uc694\uc18c\ub4e4\uc774 \uc790\uc5f0\uc2a4\ub7fd\uac8c \uc804\ud658\ub418\uc9c0 \uc54a\uace0 \uae5c\ube61\uc784 \ud604\uc0c1 \ubc1c\uc0dd","UIView \uc560\ub2c8\uba54\uc774\uc158 \ucc98\ub9ac \ucd5c\uc801\ud654 \ubc0f \uc774\ubbf8\uc9c0 \ud504\ub9ac\ub85c\ub529 \uae30\ubc95 \uc801\uc6a9. \uc804\ud658 \ud6a8\uacfc\uc6a9 \ucee4\uc2a4\ud140 \ud2b8\ub79c\uc9c0\uc158 \ud074\ub798\uc2a4 \uad6c\ud604\uc73c\ub85c \uc790\uc5f0\uc2a4\ub7ec\uc6b4 UI \ubcc0\ud654 \uad6c\ud604","iOS\uc5d0\uc11c \ub3d9\uc801 \ud14c\ub9c8 \uc804\ud658\uacfc \ubd80\ub4dc\ub7ec\uc6b4 UI \uc560\ub2c8\uba54\uc774\uc158 \uad6c\ud604 \uae30\ubc95 \uc2b5\ub4dd"),new A.d5("\ubbf8\uc138\uba3c\uc9c0 \ub370\uc774\ud130 \uc2dc\uac01\ud654 \uc131\ub2a5 \uc800\ud558","\uc2e4\uc2dc\uac04 \ubbf8\uc138\uba3c\uc9c0 \ub370\uc774\ud130\ub97c \uadf8\ub798\ud504\ub85c \ud45c\ud604\ud560 \ub54c CPU \uc0ac\uc6a9\ub7c9\uc774 \uae09\uc99d\ud558\uace0 \uc560\ub2c8\uba54\uc774\uc158\uc774 \ubc84\ubc85\uc774\ub294 \ud604\uc0c1 \ubc1c\uc0dd","\uadf8\ub798\ud53d \ub80c\ub354\ub9c1 \ub85c\uc9c1 \ucd5c\uc801\ud654 \ubc0f Core Animation \ub808\uc774\uc5b4 \uce90\uc2f1 \uc801\uc6a9. \ubcf5\uc7a1\ud55c \uadf8\ub798\ud504 \ucef4\ud3ec\ub10c\ud2b8 \uc7ac\uc124\uacc4\ub85c \ub80c\ub354\ub9c1 \ud6a8\uc728\uc131 \ud5a5\uc0c1","iOS\uc758 \uadf8\ub798\ud53d \ub80c\ub354\ub9c1 \ud30c\uc774\ud504\ub77c\uc778\uacfc \ud6a8\uc728\uc801\uc778 \uc560\ub2c8\uba54\uc774\uc158 \ucc98\ub9ac \ubc29\ubc95\uc5d0 \ub300\ud55c \uc774\ud574 \uc2ec\ud654"),new A.d5("\uc704\uce58 \ubcc0\uacbd \uc2dc \ub0a0\uc528 \ub370\uc774\ud130 \ub3d9\uae30\ud654 \uc9c0\uc5f0","\uc0ac\uc6a9\uc790\uac00 \uc9c0\uc5ed\uc744 \ubcc0\uacbd\ud560 \ub54c \ub0a0\uc528 \uc815\ubcf4\uc640 UI\uac00 \uc989\uc2dc \uc5c5\ub370\uc774\ud2b8\ub418\uc9c0 \uc54a\uc544 \uc77c\uad00\uc131 \ubb38\uc81c \ubc1c\uc0dd","\uc704\uce58 \uc5c5\ub370\uc774\ud2b8 \uc774\ubca4\ud2b8 \ud578\ub4e4\ub9c1 \uac1c\uc120 \ubc0f API \uc694\uccad \ucd5c\uc801\ud654. \ub85c\uceec \uce90\uc2f1 \uc804\ub7b5 \ub3c4\uc785\uc73c\ub85c \uc774\uc804 \uac80\uc0c9 \uc9c0\uc5ed \ub370\uc774\ud130 \ube60\ub974\uac8c \ubcf5\uc6d0","\uc0ac\uc6a9\uc790 \uc785\ub825\uc5d0 \uc989\uac01\uc801\uc73c\ub85c \ubc18\uc751\ud558\ub294 \ubc18\uc751\ud615 \uc571 \uc124\uacc4 \ubc29\ubc95\uacfc \ub370\uc774\ud130 \ub3d9\uae30\ud654 \uc804\ub7b5 \uc2b5\ub4dd")],f)
o=A.t8("\ubd80\ud2b8\ucea0\ud504 \ud300 \ud504\ub85c\uc81d\ud2b8\ub85c \uc9c4\ud589\ud558\uba74\uc11c, \ub300\ubd80\ubd84\uc758 \ub0a0\uc528 \uc571\uc774 \ub2e8\uc870\ub86d\uace0 \ub531\ub531\ud55c UI\ub97c \uac00\uc9c0\uace0 \uc788\ub2e4\ub294 \n\uc810\uc5d0 \uc8fc\ubaa9\ud588\uc2b5\ub2c8\ub2e4. \ub0a0\uc528 \uc815\ubcf4\ub294 \ub9e4\uc77c \ud655\uc778\ud558\ub294 \uc815\ubcf4\uc784\uc5d0\ub3c4 \ubd88\uad6c\ud558\uace0 \uc2dc\uac01\uc801 \uc990\uac70\uc6c0\uc774 \n\ubd80\uc871\ud558\ub2e4\uace0 \ub290\uaf08\uc2b5\ub2c8\ub2e4. \uc774\uc5d0 \uc560\ub2c8\uba54\uc774\uc158\uacfc \uc2dc\uac01\uc801 \uc694\uc18c\ub97c \ud48d\ubd80\ud558\uac8c \ud65c\uc6a9\ud55c \uadc0\uc5ec\uc6b4 \n\ub0a0\uc528 \uc571\uc744 \ub9cc\ub4e4\uc5b4 \uc0ac\uc6a9\uc790 \uacbd\ud5d8\uc744 \ud5a5\uc0c1\uc2dc\ud0a4\uace0\uc790 \ud588\uc2b5\ub2c8\ub2e4.\n",i,null,"\uae30\uc874\uc5d0 \uce59\uce59\ud55c \ub0a0\uc528 \uc571\uc744 \ub5a0\ub098 \uc5d0\ub2c8\uba54\uc774\uc158\uc5d0 \uc911\uc810\uc744 \ub454 \ub0a0\uc528 \uc571 \uc785\ub2c8\ub2e4.","https://github.com/NBCampArchive/Today-s_weather","3","images/weather.png",A.a(["improvements"],k),g,"\uc774 \ud504\ub85c\uc81d\ud2b8\ub97c \ud1b5\ud574 OpenWeatherMap API\ub97c \ud65c\uc6a9\ud55c \uc678\ubd80 \ub370\uc774\ud130 \ucc98\ub9ac\uc640 \n\ubcf5\uc7a1\ud55c \uc560\ub2c8\uba54\uc774\uc158 \uad6c\ud604 \ub2a5\ub825\uc744 \ud5a5\uc0c1\uc2dc\ud0ac \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \ud2b9\ud788 \ub0a0\uc528 \uc0c1\ud0dc\uc5d0 \ub530\ub77c \n\ub3d9\uc801\uc73c\ub85c \ubcc0\ud654\ud558\ub294 UI/UX\ub97c \uad6c\ud604\ud558\uba74\uc11c Swift \uc560\ub2c8\uba54\uc774\uc158 \uc2dc\uc2a4\ud15c\uc5d0 \ub300\ud55c \uae4a\uc740 \n\uc774\ud574\ub97c \uc5bb\uc5c8\uc2b5\ub2c8\ub2e4. \ub610\ud55c \ub0a0\uc528, \ubbf8\uc138\uba3c\uc9c0 \ub4f1 \ub2e4\uc591\ud55c \ud658\uacbd \ub370\uc774\ud130\ub97c \uc2dc\uac01\uc801\uc73c\ub85c \n\ud6a8\uacfc\uc801\uc73c\ub85c \ud45c\ud604\ud558\ub294 \ub514\uc790\uc778 \ub2a5\ub825\uc744 \ud0a4\uc6b8 \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4.\n","2024.05.14 ~ 2024.05.25",j,"openweathermap API\ub97c \ud65c\uc6a9\ud558\uc5ec \ub0a0\uc528 \uc608\ubcf4 \ubc0f \ubbf8\uc138\uba3c\uc9c0 \uce21\uc815 \uc5b4\ud50c\ub9ac\ucf00\uc774\uc158","iOS 3\uc778",h,"\uc624\ub298\uc758 \ub0a0\uc528",o)
h=A.a(["\uc601\ud654 \uc815\ubcf4 \uac80\uc0c9 \ubc0f \uc870\ud68c","\uc608\ub9e4 \uc2dc\uc2a4\ud15c","\uc0ac\uc6a9\uc790 \ub9ac\ubdf0 \uae30\ub2a5","\uac1c\uc778\ud654\ub41c \ucd94\ucc9c \uc2dc\uc2a4\ud15c"],k)
j=A.a(["UIKit","StoryBoard","RestPullAPI"],k)
g=A.a(["API \ub370\uc774\ud130 \ubaa8\ub378\ub9c1 \ubc0f \ucc98\ub9ac","\uc608\ub9e4 \uc2dc\uc2a4\ud15c \ub85c\uc9c1 \uad6c\ud604","\uc0ac\uc6a9\uc790 \ub9ac\ubdf0 \uc2dc\uc2a4\ud15c \uc124\uacc4"],k)
i=A.a(["TheMovie DB API \uc5f0\ub3d9 \ubc0f \ub370\uc774\ud130 \ubaa8\ub378\ub9c1","\uc608\ub9e4 \uc2dc\uc2a4\ud15c \ud50c\ub85c\uc6b0 \uc124\uacc4 \ubc0f \uad6c\ud604","StoryBoard \uae30\ubc18 \ud654\uba74 \uc804\ud658 \ubc0f \ub124\ube44\uac8c\uc774\uc158 \uad6c\ud604","MapKit\uc744 \ud65c\uc6a9\ud55c \uc8fc\ubcc0 \uc601\ud654\uad00 \uac80\uc0c9 \uae30\ub2a5 \uad6c\ud604","\uc8fc\ubcc0 \uc601\ud654\uad00\uae4c\uc9c0 \ub300\uc911\uad50\ud1b5 \ucc28\ub7c9 \ub3c4\ubcf4 \uacbd\ub85c \ubc0f \uc2dc\uac04 \uad6c\ud604"],k)
n=A.a([new A.d5("API \uc751\ub2f5 \ub370\uc774\ud130 \ud30c\uc2f1 \uc624\ub958","TheMovie DB API\uc5d0\uc11c \ubc1b\uc544\uc628 \ubcf5\uc7a1\ud55c JSON \uad6c\uc870\ub97c \ucc98\ub9ac\ud558\ub294 \uacfc\uc815\uc5d0\uc11c \ud2b9\uc815 \uc601\ud654 \uc815\ubcf4\uac00 \ub204\ub77d\ub418\uac70\ub098 \uc798\ubabb \ud45c\uc2dc\ub418\ub294 \ubb38\uc81c \ubc1c\uc0dd","\uacac\uace0\ud55c \ub370\uc774\ud130 \ubaa8\ub378 \uc124\uacc4 \ubc0f \uc635\uc154\ub110 \uccb4\uc774\ub2dd\uc744 \ud65c\uc6a9\ud55c \uc548\uc804\ud55c \ud30c\uc2f1 \ub85c\uc9c1 \uad6c\ud604. \uc608\uc678 \ucf00\uc774\uc2a4\uc5d0 \ub300\ud55c \ucc98\ub9ac \uac15\ud654 \ubc0f \ub370\uc774\ud130 \uac80\uc99d \ub2e8\uacc4 \ucd94\uac00","\uc678\ubd80 API \uc751\ub2f5 \ucc98\ub9ac \uc2dc \uc548\uc815\uc131\uacfc \uc624\ub958 \ub0b4\uc131\uc744 \uace0\ub824\ud55c \ubaa8\ub378\ub9c1 \ubc29\ubc95\uacfc JSON \ud30c\uc2f1 \uae30\ubc95 \uc2b5\ub4dd"),new A.d5("\uc608\ub9e4 \uc2dc\uc2a4\ud15c \ub3d9\uc2dc\uc131 \ubb38\uc81c","\ub2e4\uc218 \uc0ac\uc6a9\uc790\uac00 \ub3d9\uc2dc\uc5d0 \uac19\uc740 \uc88c\uc11d\uc744 \uc608\ub9e4\ud558\ub824 \ud560 \ub54c \uc911\ubcf5 \uc608\ub9e4 \ud604\uc0c1 \ubc1c\uc0dd","\uc88c\uc11d \uc608\uc57d \uc0c1\ud0dc \uc2e4\uc2dc\uac04 \uc5c5\ub370\uc774\ud2b8 \uba54\ucee4\ub2c8\uc998 \uad6c\ud604 \ubc0f \uc11c\ubc84 \ud1b5\uc2e0 \ucd5c\uc801\ud654. \ub099\uad00\uc801 \uc7a0\uae08\uacfc \ucda9\ub3cc \ud574\uacb0 \ub85c\uc9c1 \uc801\uc6a9\uc73c\ub85c \uc0ac\uc6a9\uc790 \uacbd\ud5d8 \uac1c\uc120","\ub3d9\uc2dc\uc131 \uc81c\uc5b4\uc640 \ubd84\uc0b0 \uc2dc\uc2a4\ud15c\uc5d0\uc11c\uc758 \ub370\uc774\ud130 \uc77c\uad00\uc131 \uc720\uc9c0 \ubc29\ubc95\uc5d0 \ub300\ud55c \uc774\ud574 \ud5a5\uc0c1"),new A.d5("\uc2a4\ud1a0\ub9ac\ubcf4\ub4dc \uae30\ubc18 UI \ud655\uc7a5\uc131 \ud55c\uacc4","\uc571 \uaddc\ubaa8\uac00 \ucee4\uc9c0\uba74\uc11c \uc2a4\ud1a0\ub9ac\ubcf4\ub4dc \uae30\ubc18 UI \uad00\ub9ac\uc758 \uc5b4\ub824\uc6c0\uacfc Git \ucda9\ub3cc \ubb38\uc81c \ubc1c\uc0dd","\uc2a4\ud1a0\ub9ac\ubcf4\ub4dc\ub97c \uae30\ub2a5\ubcc4\ub85c \ubd84\ub9ac\ud558\uace0 XIB \ud30c\uc77c \ud65c\uc6a9. \ucf54\ub4dc \uae30\ubc18 UI \ucef4\ud3ec\ub10c\ud2b8 \ub3c4\uc785\uc73c\ub85c \uc7ac\uc0ac\uc6a9\uc131 \ud5a5\uc0c1 \ubc0f \ubaa8\ub4c8\ud654 \uc124\uacc4 \uc801\uc6a9","\ub300\uaddc\ubaa8 iOS \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c\uc758 \ud6a8\uc728\uc801\uc778 UI \uad00\ub9ac \uc804\ub7b5\uacfc \ud300 \ud611\uc5c5\uc744 \uc704\ud55c \ucf54\ub4dc \uad6c\uc870\ud654 \ubc29\ubc95 \uc2b5\ub4dd")],f)
n=A.t8("\uc601\ud654 \uc815\ubcf4\ub97c \uc27d\uac8c \ucc3e\uc544\ubcf4\uace0 \uc608\ub9e4\ud560 \uc218 \uc788\ub294 \ud1b5\ud569 \ud50c\ub7ab\ud3fc\uc744 \ub9cc\ub4e4\uace0\uc790 \ud588\uc2b5\ub2c8\ub2e4.\nTheMovie DB API\ub97c \ud65c\uc6a9\ud558\uc5ec \ud48d\ubd80\ud55c \uc601\ud654 \uc815\ubcf4\ub97c \uc81c\uacf5\ud558\uace0, \n\uc0ac\uc6a9\uc790 \uce5c\ud654\uc801\uc778 \uc608\ub9e4 \uc2dc\uc2a4\ud15c\uc744 \uad6c\ud604\ud558\uace0\uc790 \ud588\uc2b5\ub2c8\ub2e4.\n",g,null,"TheMovie DB API\ub97c \ud65c\uc6a9\ud558\uc5ec \uc601\ud654 \uc815\ubcf4\ub97c \uc81c\uacf5\ud558\uace0 \uc608\ub9e4\ud560 \uc218 \uc788\ub294 \uc571\uc785\ub2c8\ub2e4.","https://github.com/NBCampArchive/CinemaApp","4","images/twelvecinema.png",A.a(["\uacb0\uc81c \uc2dc\uc2a4\ud15c \uc5f0\ub3d9","\ucd94\ucc9c \uc54c\uace0\ub9ac\uc998 \uace0\ub3c4\ud654","\uc131\ub2a5 \ucd5c\uc801\ud654"],k),h,"\uc678\ubd80 API \uc5f0\ub3d9\uacfc \ub370\uc774\ud130 \ucc98\ub9ac, UI \uad6c\ud604 \ub4f1 iOS \uc571 \uac1c\ubc1c\uc758 \n\uae30\ubcf8\uc801\uc778 \uc694\uc18c\ub4e4\uc744 \uc2e4\uc2b5\ud574\ubcfc \uc218 \uc788\uc5c8\uc2b5\ub2c8\ub2e4. \ud2b9\ud788 StoryBoard\ub97c \n\ud65c\uc6a9\ud55c UI \uac1c\ubc1c\uacfc MVC \ud328\ud134 \uc801\uc6a9\uc744 \uacbd\ud5d8\ud588\uc2b5\ub2c8\ub2e4.\n","2024.04.22 ~ 2024.04.28",i,"TheMovie DB API\ub97c \ud65c\uc6a9\ud55c \uc601\ud654 \uc815\ubcf4 \ubc0f \uc608\ub9e4 \uc2dc\uc2a4\ud15c","iOS 4\uc778",j,"Twelve Cinema",n)
j=A.a(["\uc704\uce58 \uae30\ubc18 \ud658\uacbd \ucea0\ud398\uc778 \ucc38\uc5ec","\uc2e4\uc2dc\uac04 \ud658\uacbd \ub370\uc774\ud130 \uc2dc\uac01\ud654","\uc778\uc571 \uacb0\uc81c\ub97c \ud1b5\ud55c \ucea0\ud398\uc778 \ud6c4\uc6d0","SNS \uc5f0\ub3d9 \ubc0f \uacf5\uc720 \uae30\ub2a5"],k)
i=A.a(["Flutter","Dart","Bloc","Cubit","RestPullAPI","GoogleMapAPI"],k)
h=A.a(["\uc2e4\uc2dc\uac04 \uc704\uce58 \uae30\ubc18 \uc11c\ube44\uc2a4 \uad6c\ud604 \uc2dc \uc131\ub2a5 \ucd5c\uc801\ud654 \ubb38\uc81c \ud574\uacb0","\ub2e4\uc591\ud55c \ud658\uacbd \ub370\uc774\ud130 \uc2dc\uac01\ud654\ub97c \uc704\ud55c \ucee4\uc2a4\ud140 \uc704\uc82f \uac1c\ubc1c","\ud06c\ub85c\uc2a4 \ud50c\ub7ab\ud3fc\uc5d0\uc11c\uc758 \uc77c\uad00\ub41c \uc0ac\uc6a9\uc790 \uacbd\ud5d8 \uc81c\uacf5"],k)
g=A.a(["Flutter \uac1c\ubc1c \ud300 \ub9ac\ub354\ub85c\uc11c \uc544\ud0a4\ud14d\ucc98 \uc124\uacc4 \ubc0f \ucf54\ub4dc \ub9ac\ubdf0","Bloc \ud328\ud134\uc744 \ud65c\uc6a9\ud55c \uc0c1\ud0dc \uad00\ub9ac \uc2dc\uc2a4\ud15c \uad6c\ud604","\ucc4c\ub9b0\uc9c0 \uc870\ud68c \ubc0f \uc2e0\uccad \uc2dc\uc2a4\ud15c \uad6c\ud604","\uce74\uba54\ub77c\ub97c \ud1b5\ud55c \ubbf8\uc158 \uc778\uc99d \uae30\ub2a5 \uad6c\ud604","BootPay \uacb0\uc81c \uc2dc\uc2a4\ud15c \uc5f0\ub3d9 \ubc0f \uad6c\ud604"],k)
m=A.a([new A.d5("Google Maps \ub80c\ub354\ub9c1 \uc131\ub2a5 \uc800\ud558","\ub2e4\uc218\uc758 \ucea0\ud398\uc778 \ub9c8\ucee4\uc640 \ud658\uacbd \ub370\uc774\ud130 \ub808\uc774\uc5b4\uac00 \ub85c\ub4dc\ub420 \ub54c \uc9c0\ub3c4 \ub80c\ub354\ub9c1 \uc18d\ub3c4 \uc800\ud558 \ubc0f \ud504\ub808\uc784 \ub4dc\ub78d \ubc1c\uc0dd","\ub9c8\ucee4 \ud074\ub7ec\uc2a4\ud130\ub9c1 \uae30\ubc95 \ub3c4\uc785 \ubc0f \ubdf0\ud3ec\ud2b8 \uae30\ubc18 \ub370\uc774\ud130 \ub85c\ub529 \uad6c\ud604. \uc9c0\ub3c4 \ud0c0\uc77c \uce90\uc2f1 \ubc0f \uc560\uc14b \ucd5c\uc801\ud654\ub85c \ucd08\uae30 \ub85c\ub529 \uc18d\ub3c4 \ud5a5\uc0c1","\ubaa8\ubc14\uc77c \ud658\uacbd\uc5d0\uc11c \uc9c0\ub3c4 \uae30\ubc18 \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc758 \uc131\ub2a5 \ucd5c\uc801\ud654 \uc804\ub7b5\uacfc \uc0ac\uc6a9\uc790 \uacbd\ud5d8 \ud5a5\uc0c1 \uae30\ubc95 \uc2b5\ub4dd"),new A.d5("Flutter \uc778\uc571\uacb0\uc81c \uad6c\ud604\uc744 \uc704\ud55c \uac1c\ubc1c\uc790 \uacc4\uc815 \uc81c\uc57d \ubb38\uc81c","Flutter \uc571\uc5d0 \uacb0\uc81c \uae30\ub2a5\uc744 \ub3c4\uc785\ud558\ub824 \ud588\uc73c\ub098, \uacf5\uc2dd \uc778\uc571\uacb0\uc81c \uad6c\ud604\uc5d0 \ud544\uc694\ud55c \uac1c\ubc1c\uc790 \uacc4\uc815 \uc81c\uc57d\uacfc \ubcf5\uc7a1\ud55c \uc2b9\uc778 \uacfc\uc815\uc73c\ub85c \uac1c\ubc1c \uc77c\uc815 \uc9c0\uc5f0 \uc704\uae30 \ubc1c\uc0dd","PG\uc0ac \ub300\ud589 \uacb0\uc81c \uc11c\ube44\uc2a4\uc778 BootPay\ub97c \ub3c4\uc785\ud558\uc5ec \uac1c\ubc1c\uc790 \uacc4\uc815 \uc5c6\uc774\ub3c4 \uc548\uc815\uc801\uc778 \uacb0\uc81c \uc2dc\uc2a4\ud15c \uad6c\ud604. \uacb0\uc81c \ud504\ub85c\uc138\uc2a4\ub97c \uac04\uc18c\ud654\ud558\uace0 \ub2e4\uc591\ud55c \uacb0\uc81c \uc218\ub2e8\uc744 \uc9c0\uc6d0\ud558\ub294 \ud1b5\ud569 \uc194\ub8e8\uc158 \uc801\uc6a9","\ubaa8\ubc14\uc77c \uc571\uc758 \uacb0\uc81c \uc2dc\uc2a4\ud15c \uc124\uacc4 \uc2dc \ud50c\ub7ab\ud3fc\ubcc4 \uc815\ucc45 \uc81c\uc57d\uc744 \uace0\ub824\ud55c \ub300\uccb4 \uc194\ub8e8\uc158 \ub3c4\uc785 \uc804\ub7b5\uacfc \uc81c3\uc790 \uacb0\uc81c \uc11c\ube44\uc2a4 \uc5f0\ub3d9 \uc544\ud0a4\ud14d\ucc98 \uad6c\ud604 \ubc29\ubc95 \uc2b5\ub4dd"),new A.d5("Bloc \ud328\ud134 \uc0ac\uc6a9 \uc2dc \uc0c1\ud0dc \uad00\ub9ac \ubcf5\uc7a1\uc131","\uc571 \uaddc\ubaa8 \ud655\uc7a5\uc5d0 \ub530\ub77c \uc0c1\ud0dc \uad00\ub9ac \ub85c\uc9c1\uc774 \ubcf5\uc7a1\ud574\uc9c0\uba74\uc11c \uc608\uc0c1\uce58 \ubabb\ud55c UI \uc5c5\ub370\uc774\ud2b8 \ubb38\uc81c \ubc0f \ub514\ubc84\uae45 \uc5b4\ub824\uc6c0 \ubc1c\uc0dd","Bloc \uc544\ud0a4\ud14d\ucc98 \uc7ac\uc124\uacc4 \ubc0f \uc0c1\ud0dc \uad00\ub9ac \ub2e8\uc21c\ud654. \uba85\ud655\ud55c \uc774\ubca4\ud2b8-\uc0c1\ud0dc \ubaa8\ub378\ub9c1\uacfc \ub2e8\ubc29\ud5a5 \ub370\uc774\ud130 \ud750\ub984 \uc801\uc6a9\uc73c\ub85c \uc608\uce21 \uac00\ub2a5\ud55c \uc0c1\ud0dc \ubcc0\ud654 \uad6c\ud604","\ub300\uaddc\ubaa8 Flutter \uc560\ud50c\ub9ac\ucf00\uc774\uc158\uc5d0\uc11c\uc758 \ud6a8\uacfc\uc801\uc778 \uc0c1\ud0dc \uad00\ub9ac \uc804\ub7b5\uacfc Bloc \ud328\ud134\uc758 \uc2e4\uc804\uc801 \ud65c\uc6a9 \ubc29\ubc95 \uc2b5\ub4dd")],f)
m=A.t8("Google Solution Challenge\uc5d0\uc11c UN SDGs \uc911 '\uae30\ud6c4\ubcc0\ud654 \ub300\uc751'\uc744 \uc8fc\uc81c\ub85c \uc120\uc815\ud558\uc5ec,\n\uc77c\ubc18 \uc2dc\ubbfc\ub4e4\uc774 \uc27d\uac8c \ud658\uacbd \ubcf4\ud638 \ud65c\ub3d9\uc5d0 \ucc38\uc5ec\ud560 \uc218 \uc788\ub294 \ud50c\ub7ab\ud3fc\uc758 \ud544\uc694\uc131\uc744 \uc778\uc2dd\ud558\uace0 \uac1c\ubc1c\uc744 \uc2dc\uc791\ud588\uc2b5\ub2c8\ub2e4.\n",h,"https://www.youtube.com/watch?v=yYz4czlmn0Q","ZIKIZA\ub294 \ubbf8\ub77c\ud074 \ucc4c\ub9b0\uc9c0\uc640 \uac19\uc740 \uc11c\ube44\uc2a4\uc5d0 \uc601\ud5a5\uc744 \ubc1b\uc544 \ud658\uacbd \ubcf4\ud638 \ud65c\ub3d9\uc744 \ucc4c\ub9b0\uc9c0\ud654 \ud558\uc5ec \uc0ac\uc6a9\uc790\ub4e4\uc758 \ucc38\uc5ec\ub97c \uc720\ub3c4\ud558\ub294 \ud50c\ub7ab\ud3fc\uc785\ub2c8\ub2e4.\n\uc704\uce58 \uae30\ubc18 \uc11c\ube44\uc2a4\ub97c \ud1b5\ud574 \uc8fc\ubcc0\uc758 \ud658\uacbd \ucea0\ud398\uc778\uc744 \ud655\uc778\ud558\uace0 \ucc38\uc5ec\ud560 \uc218 \uc788\uc73c\uba70,\n\uc2e4\uc2dc\uac04\uc73c\ub85c \ud658\uacbd \ub370\uc774\ud130\ub97c \uc2dc\uac01\ud654\ud558\uc5ec \uc81c\uacf5\ud569\ub2c8\ub2e4.\n","https://github.com/GDG-on-Campus-SKHU/98developers-flutter-app","5","images/zikiza.png",A.a(["\uc624\ud504\ub77c\uc778 \uce90\uc2f1 \uae30\ub2a5 \ucd94\uac00 \ud544\uc694","\ud658\uacbd \ub370\uc774\ud130 \ubd84\uc11d \uae30\ub2a5 \uac15\ud654","\ucee4\ubba4\ub2c8\ud2f0 \uae30\ub2a5 \ud655\uc7a5"],k),j,"\ubcf8 \ud504\ub85c\uc81d\ud2b8\ub97c \ud1b5\ud574 Flutter\ub97c \ud65c\uc6a9\ud55c \ud06c\ub85c\uc2a4 \ud50c\ub7ab\ud3fc \uac1c\ubc1c \uacbd\ud5d8\uc744 \uc313\uc558\uc73c\uba70,\n\ud2b9\ud788 Google Maps API\uc640 \uc2e4\uc2dc\uac04 \ub370\uc774\ud130 \ucc98\ub9ac\uc5d0 \ub300\ud55c \uae30\uc220\uc801 \uc5ed\ub7c9\uc744 \ud5a5\uc0c1\uc2dc\ucf30\uc2b5\ub2c8\ub2e4.\n\ub610\ud55c \ud300 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c Flutter \uac1c\ubc1c \ud30c\ud2b8 \ub9ac\ub354\ub85c\uc11c \ucf54\ub4dc \ub9ac\ubdf0\uc640 \uc544\ud0a4\ud14d\ucc98 \uc124\uacc4\ub97c \uc8fc\ub3c4\ud588\uc2b5\ub2c8\ub2e4.\n","2023.02.15 ~ 2023.04.01",g,"UN \uc9c0\uc18d\uac00\ub2a5\ud55c \uac1c\ubc1c \ubaa9\ud45c(SDGs)\ub97c \uc704\ud55c \ud658\uacbd \ucea0\ud398\uc778 \ud50c\ub7ab\ud3fc","Flutter 2\uc778, Back-end 1\uc778",i,"ZIKIZA",m)
i=A.a(["\uad6d\uac00\ubcc4 \ud034\uc988 \uc2dc\uc2a4\ud15c","\uc2e4\uc2dc\uac04 \uc810\uc218 \uc2dc\uc2a4\ud15c","\uad50\uc721\uc801 \ucf58\ud150\uce20 \uc81c\uacf5","\uc778\ud130\ub799\ud2f0\ube0c UI/UX"],k)
g=A.a(["Flutter","Dart","RestPullAPI"],k)
j=A.a(["\ud034\uc988 \uc2dc\uc2a4\ud15c \uc124\uacc4","\uc2e4\uc2dc\uac04 \uc810\uc218 \ucc98\ub9ac","\uad50\uc721\uc801 \uc694\uc18c\uc640 \uac8c\uc784\uc801 \uc694\uc18c\uc758 \uade0\ud615"],k)
